1	// R8 — Oracle chat route (refactored through OracleAIClient).
2	//
3	// Per docs/oracle/05-ai-retrofit-phase-packet.md Phase R8.
4	//
5	// What changed vs the legacy route:
6	//   - The model call goes through OracleAIClient.runText via the direct
7	//     provider adapters (Vertex / Anthropic / OpenAI raw SDKs —
8	//     DECISIONS.md D6 / D9) using the curated interview route from
9	//     `settings.default_interview_route` (R1 setting key) — not via
10	//     `getOpenRouter()` directly.
11	//   - oracle_context_packs + model_run_usage_details rows are written
12	//     for every chat turn so cache-hit / fallback dashboards work.
13	//   - The chat route executes retrieval deterministically before the model call
14	//     (recent messages, open gaps, approved claims); multi-turn message history
15	//     and temperature are passed through providerOptions.
16	//
17	// What stays the same:
18	//   - Auth + channel-participation check.
19	//   - Direct-mention gate for group chats (spec Part 10 group chat rules).
20	//   - Retrieval bundle: recent messages, employee profile, top open gaps,
21	//     top relevant approved claims. No full Brain stuffing.
22	//   - Vision-capable model detection + selective attachment downloads.
23	//   - Assistant message inserted via service-role client.
24	
25	import { NextResponse, type NextRequest } from 'next/server';
26	import { eq, and, inArray } from 'drizzle-orm';
27	import { desc } from 'drizzle-orm';
28	import { createHash } from 'node:crypto';
29	import { writeFile, unlink } from 'node:fs/promises';
30	import { tmpdir } from 'node:os';
31	import { join } from 'node:path';
32	import { z } from 'zod';
33	import { createServiceRoleClient } from '@oracle/auth/server';
34	import {
35	  ORACLE_SYSTEM_PROMPT,
36	  ORACLE_SYSTEM_PROMPT_VERSION,
37	  OracleAIClient,
38	  buildStandardAdapters,
39	  getOracleRoute,
40	  resolveRouteFromSettings,
41	  getRecentMessages,
42	  getRelevantOpenGaps,
43	  makeBlock,
44	  searchWithRetrievalPlan,
45	  buildRetrievalPlanFromQuery,
46	  type OracleModelRoute,
47	  type OraclePromptPlan,
48	  type RetrievalPlanSearchScope,
49	} from '@oracle/ai';
50	import { getDirectDb } from '@oracle/db/client';
51	import {
52	  channels,
53	  channelParticipants,
54	  documents,
55	  employeeIdentities,
56	  employees,
57	  messageAttachments,
58	  messages,
59	  modelRunUsageDetails,
60	  modelRuns,
61	  oracleContextPacks,
62	  providerResponseSessions,
63	  settings,
64	  type OracleDb,
65	} from '@oracle/db';
66	import { getServerSupabase } from '@/lib/supabase/server';
67	
68	const BodySchema = z.object({
69	  channelId: z.uuid(),
70	  force: z.boolean().optional(),
71	});
72	
73	const FALLBACK_ROUTE_ID = 'anthropic_claude_haiku_4_5_interview_primary';
74	
75	// Minimum size for routing a chat-attached PDF through the Vertex GCS
76	// file-backed cache. Below this, Gemini's explicit-cache minimum-token floor
77	// makes caching unprofitable (and risky — see route logic), so we leave small
78	// files on the inline path.
79	const VERTEX_CHAT_FILE_CACHE_MIN_BYTES = 256 * 1024;
80	
81	// Lazy singleton OracleAIClient with direct provider adapters (R-providers).
82	// Anthropic / Vertex / OpenAI raw SDKs per DECISIONS.md D6 — no Vercel AI
83	// SDK, no OpenRouter in this path.
84	//
85	// The adapter constructors throw when their provider API key is missing, so
86	// we MUST defer instantiation until the first request. At Next.js build time,
87	// the "Collect page data" phase imports this module without the runtime env
88	// vars in scope — eagerly constructing the singleton there fails the build.
89	let _oracleClient: OracleAIClient | null = null;
90	function getOracleClient(): OracleAIClient {
91	  if (!_oracleClient) {
92	    _oracleClient = new OracleAIClient({
93	      adapters: buildStandardAdapters(),
94	      fallbackOnError: true,
95	    });
96	  }
97	  return _oracleClient;
98	}
99	
100	export async function POST(req: NextRequest) {
101	  let body: z.infer<typeof BodySchema>;
102	  try {
103	    body = BodySchema.parse(await req.json());
104	  } catch (err) {
105	    return NextResponse.json({ error: 'bad_request', detail: String(err) }, { status: 400 });
106	  }
107	
108	  // ── 1. Auth ──────────────────────────────────────────────────────────
109	  const supabase = await getServerSupabase();
110	  const { data: userData } = await supabase.auth.getUser();
111	  if (!userData.user) {
112	    return NextResponse.json({ error: 'unauthenticated' }, { status: 401 });
113	  }
114	
115	  const db = getDirectDb();
116	  const meRows = await db
117	    .select({ employee: employees })
118	    .from(employees)
119	    .innerJoin(employeeIdentities, eq(employeeIdentities.employeeId, employees.id))
120	    .where(eq(employeeIdentities.authUserId, userData.user.id))
121	    .limit(1);
122	  const me = meRows[0]?.employee;
123	  if (!me || me.disabledAt) {
124	    return NextResponse.json({ error: 'not_approved' }, { status: 403 });
125	  }
126	
127	  // ── 2. Channel membership + group-chat detection ─────────────────────
128	  const [membership, channelRows] = await Promise.all([
129	    db
130	      .select()
131	      .from(channelParticipants)
132	      .where(
133	        and(
134	          eq(channelParticipants.channelId, body.channelId),
135	          eq(channelParticipants.employeeId, me.id),
136	        ),
137	      )
138	      .limit(1),
139	    db
140	      .select({ isGroupChat: channels.isGroupChat })
141	      .from(channels)
142	      .where(eq(channels.id, body.channelId))
143	      .limit(1),
144	  ]);
145	  if (membership.length === 0) {
146	    return NextResponse.json({ error: 'not_in_channel' }, { status: 403 });
147	  }
148	  const isGroupChat = channelRows[0]?.isGroupChat ?? false;
149	
150	  // ── 3. Retrieval bundle ──────────────────────────────────────────────
151	  const recent = await getRecentMessages(db, body.channelId);
152	  if (recent.length === 0) {
153	    return NextResponse.json(
154	      { error: 'no_user_message', detail: 'Channel has no messages.' },
155	      { status: 400 },
156	    );
157	  }
158	
159	  // Direct-mention gate (group chats only; DM is always direct).
160	  const latestUserMessage = [...recent].reverse().find((m) => m.role === 'user');
161	  if (!latestUserMessage) {
162	    return NextResponse.json({ ok: true, skipped: 'no_user_message' });
163	  }
164	  if (!body.force && isGroupChat) {
165	    if (!/^\s*(@oracle\b|oracle,)/i.test(latestUserMessage.content)) {
166	      return NextResponse.json({ ok: true, skipped: 'no_direct_mention' });
167	    }
168	  }
169	
170	  const openGaps = await getRelevantOpenGaps(db, me);
171	  // Build a RetrievalPlan from the latest message — applies domain-hint inference,
172	  // entity-type exclusions, and document-class exclusions before vector search
173	  // (spec docs/oracle/07-knowledge-segmentation.md "Retrieval rule").
174	  const queryForClaims = latestUserMessage.content;
175	  // Use the employee's departments as a soft RRF bonus — not a filter.
176	  // Falls back to legacy single `department` field if `departments` is empty.
177	  const deptHints =
178	    me.departments.length > 0
179	      ? me.departments
180	      : me.department ? [me.department] : [];
181	  const retrievalPlan = buildRetrievalPlanFromQuery(queryForClaims, {
182	    topK: 8,
183	    departmentHints: deptHints,
184	  });
185	  const relevantClaims = queryForClaims
186	    ? await searchWithRetrievalPlan(db, retrievalPlan)
187	    : [];
188	
189	  // ── 4. Resolve curated interview route ───────────────────────────────
190	  const route = await resolveInterviewRoute(db);
191	  const visionCapable = isVisionCapableRoute(route);
192	
193	  // ── 5. Compile prompt blocks (stable system + dynamic context) ───────
194	  const contextLines: string[] = [];
195	  contextLines.push(`---\nCONTEXT FOR THIS TURN:`);
196	  const deptDisplay = me.departments.length > 0
197	    ? me.departments.join(', ')
198	    : (me.department ?? 'Unknown');
199	  contextLines.push(`You are speaking with ${me.name} (${me.role}, ${deptDisplay}).`);
200	  if (openGaps.length > 0) {
201	    contextLines.push(`\nOpen gaps you may weave in if relevant:`);
202	    for (const g of openGaps) {
203	      contextLines.push(`- [${g.priority}] ${g.questionToAsk}`);
204	    }
205	  }
206	  if (relevantClaims.length > 0) {
207	    contextLines.push(`\nApproved claims that may be relevant:`);
208	    for (const c of relevantClaims) {
209	      contextLines.push(`- ${c.summary} (impact ${c.impactScore})`);
210	    }
211	  }
212	  const dynamicContext = contextLines.join('\n');
213	
214	  const blocks = [
215	    makeBlock({
216	      id: 'oracle-system',
217	      label: 'Oracle interview system prompt',
218	      kind: 'stable_system',
219	      content: ORACLE_SYSTEM_PROMPT,
220	      reasonIncluded: 'oracle prompt v' + ORACLE_SYSTEM_PROMPT_VERSION,
221	    }),
222	    makeBlock({
223	      id: 'turn-context',
224	      label: 'Per-turn retrieval bundle (employee + gaps + relevant claims)',
225	      kind: 'retrieved_context',
226	      content: dynamicContext,
227	      reasonIncluded: `gaps=${openGaps.length}, claims=${relevantClaims.length}`,
228	    }),
229	  ];
230	
231	  const plan = getOracleClient().compile({
232	    taskType: 'interview_chat',
233	    routeId: route.routeId,
234	    promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
235	    blocks,
236	    observability: {
237	      includedMessageIds: recent.map((m) => m.id),
238	      includedGapIds: openGaps.map((g) => g.id),
239	      includedClaimIds: relevantClaims.map((c) => c.id),
240	      // Retrieval scope audit — stored in oracle_context_packs.selected_domains.
241	      // domain_filtered → actual domain IDs used for pre-filtering.
242	      // global_fallback → '_global_fallback' tag; query
243	      //   WHERE selected_domains @> ARRAY['_global_fallback'] to find heuristic gaps.
244	      // global_explicit → '_global_explicit' tag (intentional wide search).
245	      selectedDomains: scopeTag(retrievalPlan.topDomainHints, retrievalPlan.searchScope),
246	    },
247	  });
248	
249	  // ── 6. Stage context pack BEFORE the model call ──────────────────────
250	  const [contextPack] = await db
251	    .insert(oracleContextPacks)
252	    .values(buildContextPackInsert(plan))
253	    .returning({ id: oracleContextPacks.id });
254	  if (!contextPack) {
255	    return NextResponse.json({ error: 'context_pack_failed' }, { status: 500 });
256	  }
257	
258	  // ── 7. Build multi-turn conversation (with attachments for vision routes) ─
259	  const recentIds = recent.map((m) => m.id);
260	  const attachmentRows =
261	    visionCapable && recentIds.length > 0
262	      ? await db
263	          .select({
264	            messageId: messageAttachments.messageId,
265	            storageBucket: documents.storageBucket,
266	            storagePath: documents.storagePath,
267	            fileType: documents.fileType,
268	            fileName: documents.fileName,
269	          })
270	          .from(messageAttachments)
271	          .innerJoin(documents, eq(documents.id, messageAttachments.documentId))
272	          .where(inArray(messageAttachments.messageId, recentIds))
273	      : [];
274	
275	  type AttRow = (typeof attachmentRows)[number];
276	  const attachmentMap = new Map<string, AttRow[]>();
277	  for (const att of attachmentRows) {
278	    const list = attachmentMap.get(att.messageId) ?? [];
279	    list.push(att);
280	    attachmentMap.set(att.messageId, list);
281	  }
282	
283	  const serviceSupabase = createServiceRoleClient();
284	
285	  // ── 7a. Vertex GCS file-backed cache for a large attached PDF ────────
286	  // When the interview route runs on Vertex AND a GCS cache bucket is
287	  // configured, cache the most-recent large PDF in the thread as a Gemini
288	  // cachedContent prefix (gs:// fileData) instead of re-sending it as base64
289	  // on every turn. The conversation turns ride on top of the cache as live
290	  // text contents (the adapter preserves multi-turn history on the file-cache
291	  // path). When this activates we EXCLUDE inline attachment parts so the doc
292	  // is not double-sent; v1 limitation: only this single cached document is
293	  // provided to the model, other attachments are not separately inlined.
294	  //
295	  // Gated on the bucket env: without it the adapter no-ops the file path, so
296	  // excluding the inline copy would leave the model with no document at all.
297	  const fileCacheEnabled =
298	    route.provider === 'vertex' && !!process.env.GOOGLE_VERTEX_CONTEXT_CACHE_GCS_BUCKET;
299	  let vertexFileCacheSource:
300	    | { localPath: string; mimeType: string; fileName: string; sourceHash: string }
301	    | undefined;
302	  let cachedTempPath: string | undefined;
303	  if (fileCacheEnabled) {
304	    const candidate = pickCacheablePdf(recent, attachmentMap);
305	    if (candidate) {
306	      try {
307	        const { data: blob, error } = await serviceSupabase.storage
308	          .from(candidate.storageBucket)
309	          .download(candidate.storagePath);
310	        if (error || !blob) {
311	          console.warn('[chat] file-cache candidate download failed', candidate.storagePath, error?.message);
312	        } else {
313	          const buf = Buffer.from(await blob.arrayBuffer());
314	          if (buf.length >= VERTEX_CHAT_FILE_CACHE_MIN_BYTES) {
315	            cachedTempPath = await materializeVertexCacheTempFile(buf, candidate.fileName);
316	            vertexFileCacheSource = {
317	              localPath: cachedTempPath,
318	              mimeType: candidate.fileType,
319	              fileName: candidate.fileName,
320	              // `documents` has no content hash column — hash the bytes so the
321	              // cache key + GCS object name are stable across turns (enables reuse).
322	              sourceHash: createHash('sha256').update(buf).digest('hex'),
323	            };
324	          }
325	        }
326	      } catch (err) {
327	        console.warn('[chat] file-cache candidate preparation failed', candidate.storagePath, err);
328	      }
329	    }
330	  }
331	  // Only exclude inline attachment parts once we are certain the file cache
332	  // will carry the document; otherwise keep the existing inline behavior.
333	  const excludeInlineAttachments = !!vertexFileCacheSource;
334	
335	  type ChatContentPart =
336	    | { type: 'text'; text: string }
337	    | { type: 'image'; image: string }
338	    | { type: 'file'; data: string; mimeType: string };
339	  type ConversationMessage = {
340	    role: 'user' | 'assistant';
341	    content: string | ChatContentPart[];
342	  };
343	
344	  const conversationMessages: ConversationMessage[] = await Promise.all(
345	    recent
346	      .filter((m) => m.role !== 'system')
347	      .map(async (m) => {
348	        const role = m.role === 'assistant' ? ('assistant' as const) : ('user' as const);
349	        const textContent =
350	          m.role === 'user' && m.authorName ? `[${m.authorName}] ${m.content}` : m.content;
351	        const atts = attachmentMap.get(m.id) ?? [];
352	        if (atts.length === 0 || excludeInlineAttachments) return { role, content: textContent };
353	
354	        const parts: ChatContentPart[] = [{ type: 'text', text: textContent }];
355	        for (const att of atts) {
356	          try {
357	            const { data: blob, error } = await serviceSupabase.storage
358	              .from(att.storageBucket)
359	              .download(att.storagePath);
360	            if (error || !blob) {
361	              console.warn('[chat] could not download attachment', att.storagePath, error?.message);
362	              continue;
363	            }
364	            const buf = Buffer.from(await blob.arrayBuffer());
365	            const b64 = buf.toString('base64');
366	            if (att.fileType.startsWith('image/')) {
367	              parts.push({ type: 'image', image: `data:${att.fileType};base64,${b64}` });
368	            } else if (att.fileType === 'application/pdf') {
369	              parts.push({ type: 'file', data: b64, mimeType: 'application/pdf' });
370	            } else if (att.fileType.startsWith('text/')) {
371	              const text = buf.toString('utf8');
372	              parts.push({ type: 'text', text: `\n\n[File: ${att.fileName}]\n${text}\n[/File]` });
373	            }
374	          } catch (err) {
375	            console.error('[chat] attachment fetch failed', att.storagePath, err);
376	          }
377	        }
378	        return { role, content: parts.length === 1 ? textContent : parts };
379	      }),
380	  );
381	
382	  const safeMessages: ConversationMessage[] = visionCapable
383	    ? conversationMessages
384	    : conversationMessages.map((m) => {
385	        if (!Array.isArray(m.content)) return m;
386	        const textOnly = m.content
387	          .filter((p): p is { type: 'text'; text: string } => p.type === 'text')
388	          .map((p) => p.text)
389	          .join('\n');
390	        return { ...m, content: textOnly };
391	      });
392	
393	  // ── 8. Dispatch through OracleAIClient ───────────────────────────────
394	  const startedAt = Date.now();
395	  const qwenSessionKey = route.provider === 'qwen' ? `interview-chat:${body.channelId}` : null;
396	  const previousQwenSession =
397	    qwenSessionKey
398	      ? await db
399	          .select({
400	            latestResponseId: providerResponseSessions.latestResponseId,
401	            modelId: providerResponseSessions.modelId,
402	          })
403	          .from(providerResponseSessions)
404	          .where(
405	            and(
406	              eq(providerResponseSessions.provider, 'qwen'),
407	              eq(providerResponseSessions.sessionKey, qwenSessionKey),
408	            ),
409	          )
410	          .orderBy(desc(providerResponseSessions.updatedAt))
411	          .limit(1)
412	      : [];
413	  let oracleText = '';
414	  let inputTokens: number | undefined;
415	  let outputTokens: number | undefined;
416	  let cachedInputTokens: number | undefined;
417	  let modelError: string | undefined;
418	  let success = false;
419	  let usageRaw: unknown = null;
420	  let providerRequestId: string | undefined;
421	  let actualRouteId = route.routeId;
422	  let actualProvider = route.provider;
423	  let actualModelId = route.modelId;
424	  let fellBackFromRouteId: string | undefined;
425	  let fallbackReason: string | undefined;
426	
427	  try {
428	    const messagesWithContext = [
429	      {
430	        role: 'user' as const,
431	        content:
432	          '[Oracle runtime context - not part of the employee chat transcript]\n' +
433	          dynamicContext,
434	      },
435	      ...safeMessages,
436	    ];
437	    const result = await getOracleClient().runText({
438	      taskType: 'interview_chat',
439	      routeId: route.routeId,
440	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
441	      blocks,
442	      observability: {
443	        includedMessageIds: recent.map((m) => m.id),
444	        includedGapIds: openGaps.map((g) => g.id),
445	        includedClaimIds: relevantClaims.map((c) => c.id),
446	      },
447	      providerOptions: {
448	        messages: messagesWithContext,
449	        temperature: 0.4,
450	        cache: {
451	          preferLongLivedCache: true,
452	          // 30 min when caching an attached document for an active chat;
453	          // otherwise the default short interview-context TTL.
454	          cacheTtlSeconds: vertexFileCacheSource ? 30 * 60 : 10 * 60,
455	          expectedReuseCount: 6,
456	          // Activates the adapter's explicit file-cache path (Vertex only).
457	          preferExplicitCache: !!vertexFileCacheSource,
458	          persistProviderCacheRecord: route.provider === 'vertex',
459	          sourceDescription: `channel ${body.channelId} interview context`,
460	          cleanupOwner: 'chat-route',
461	          latestPlannedReuseStep: 'interview_chat',
462	          vertexFileCacheSource,
463	          sessionCacheKey:
464	            qwenSessionKey ?? undefined,
465	          previousResponseId:
466	            route.provider === 'qwen'
467	              ? previousQwenSession[0]?.modelId === route.modelId
468	                ? previousQwenSession[0]?.latestResponseId
469	                : undefined
470	              : undefined,
471	        },
472	      },
473	    });
474	    oracleText = result.text;
475	    inputTokens = result.usage.inputTokens;
476	    outputTokens = result.usage.outputTokens;
477	    cachedInputTokens = result.usage.cachedInputTokens;
478	    usageRaw = result.usage.rawUsageJson;
479	    providerRequestId = result.usage.providerRequestId;
480	    actualRouteId = result.routeId ?? route.routeId;
481	    actualProvider = (result.provider as typeof route.provider | undefined) ?? route.provider;
482	    actualModelId = result.modelId ?? route.modelId;
483	    fellBackFromRouteId = result.fellBackFromRouteId;
484	    fallbackReason = result.fallbackReason;
485	    success = true;
486	  } catch (err) {
487	    modelError = err instanceof Error ? err.message : String(err);
488	    console.error('[chat] model error', err);
489	  } finally {
490	    // The GCS object is reaped by the adapter's cache-TTL sweeper; we only own
491	    // the local temp file. Best-effort cleanup.
492	    if (cachedTempPath) {
493	      await unlink(cachedTempPath).catch(() => undefined);
494	    }
495	  }
496	
497	  // ── 9. Log model_runs + model_run_usage_details + back-link pack ───
498	  const [modelRun] = await db
499	    .insert(modelRuns)
500	    .values({
501	      taskType: 'interview_chat',
502	      model: actualModelId,
503	      provider: actualProvider,
504	      promptVersion: ORACLE_SYSTEM_PROMPT_VERSION,
505	      inputHash: plan.metadata.stablePrefixHash,
506	      inputTokens: inputTokens ?? null,
507	      outputTokens: outputTokens ?? null,
508	      latencyMs: Date.now() - startedAt,
509	      success,
510	      error: modelError ?? null,
511	    })
512	    .returning({ id: modelRuns.id });
513	
514	  if (modelRun) {
515	    await db.insert(modelRunUsageDetails).values({
516	      modelRunId: modelRun.id,
517	      contextPackId: contextPack.id,
518	      routeId: actualRouteId,
519	      inputTokens: inputTokens ?? null,
520	      cachedInputTokens: cachedInputTokens ?? null,
521	      outputTokens: outputTokens ?? null,
522	      providerRequestId: providerRequestId ?? null,
523	      rawUsageJson: usageRaw ?? null,
524	      fellBackFromRouteId: fellBackFromRouteId ?? null,
525	      fallbackReason: fallbackReason ?? null,
526	    });
527	    await db
528	      .update(oracleContextPacks)
529	      .set({ modelRunId: modelRun.id })
530	      .where(eq(oracleContextPacks.id, contextPack.id));
531	
532	    if (actualProvider === 'qwen' && providerRequestId && qwenSessionKey) {
533	      await db
534	        .insert(providerResponseSessions)
535	        .values({
536	          provider: 'qwen',
537	          sessionKey: qwenSessionKey,
538	          scopeKind: 'channel',
539	          scopeId: body.channelId,
540	          modelId: actualModelId,
541	          latestResponseId: providerRequestId,
542	          lastContextPackId: contextPack.id,
543	          lastModelRunId: modelRun.id,
544	          metadataJson: {
545	            routeId: actualRouteId,
546	          },
547	        })
548	        .onConflictDoUpdate({
549	          target: [
550	            providerResponseSessions.provider,
551	            providerResponseSessions.sessionKey,
552	          ],
553	          set: {
554	            modelId: actualModelId,
555	            latestResponseId: providerRequestId,
556	            lastContextPackId: contextPack.id,
557	            lastModelRunId: modelRun.id,
558	            metadataJson: {
559	              routeId: actualRouteId,
560	            },
561	            updatedAt: new Date(),
562	          },
563	        });
564	    }
565	  }
566	
567	  if (!success || !oracleText.trim()) {
568	    return NextResponse.json(
569	      { error: 'model_failed', detail: modelError ?? 'empty response' },
570	      { status: 502 },
571	    );
572	  }
573	
574	  // ── 10. Persist Oracle reply as assistant message ───────────────────
575	  const [inserted] = await db
576	    .insert(messages)
577	    .values({
578	      channelId: body.channelId,
579	      employeeId: null,
580	      role: 'assistant',
581	      content: oracleText.trim(),
582	      extractionStatus: 'skipped',
583	    })
584	    .returning();
585	
586	  return NextResponse.json({
587	    ok: true,
588	    messageId: inserted?.id,
589	    routeId: actualRouteId,
590	    model: actualModelId,
591	    provider: actualProvider,
592	    contextPackId: contextPack.id,
593	    modelRunId: modelRun?.id ?? null,
594	    latencyMs: Date.now() - startedAt,
595	  });
596	}
597	
598	// ─────────────────────────────────────────────────────────────────────────
599	// Helpers
600	// ─────────────────────────────────────────────────────────────────────────
601	
602	/**
603	 * Build the selectedDomains array for the context pack.
604	 * - domain_filtered: return the actual domain IDs.
605	 * - global_fallback / global_explicit: return a single sentinel tag so
606	 *   operators can query: WHERE selected_domains @> ARRAY['_global_fallback'].
607	 */
608	function scopeTag(topDomainHints: string[], scope: RetrievalPlanSearchScope): string[] {
609	  if (topDomainHints.length > 0) return topDomainHints;
610	  return [`_${scope}`]; // '_global_fallback' or '_global_explicit'
611	}
612	
613	async function resolveInterviewRoute(db: OracleDb): Promise<OracleModelRoute> {
614	  // resolveRouteFromSettings handles catalog routeIds, OpenRouter "provider/model"
615	  // IDs from the pool picker, AND attaches the admin's saved reasoning effort.
616	  const resolved = await resolveRouteFromSettings(db, 'interview');
617	  if (resolved) return resolved;
618	  const fb = getOracleRoute(FALLBACK_ROUTE_ID);
619	  if (!fb) {
620	    throw new Error(
621	      `[chat] default_interview_route unset/unresolvable and fallback "${FALLBACK_ROUTE_ID}" missing.`,
622	    );
623	  }
624	  console.warn(`[chat] default_interview_route unset/unresolvable; using fallback "${FALLBACK_ROUTE_ID}".`);
625	  return fb;
626	}
627	
628	/**
629	 * Pick at most ONE document to route through the Vertex GCS file cache: the
630	 * most-recent PDF attachment in the recent-message window. Walks newest→oldest
631	 * so an attachment on the latest turn wins.
632	 */
633	function pickCacheablePdf<T extends { fileType: string }>(
634	  recentMessages: Array<{ id: string }>,
635	  attachmentMap: Map<string, T[]>,
636	): T | null {
637	  for (let i = recentMessages.length - 1; i >= 0; i -= 1) {
638	    const atts = attachmentMap.get(recentMessages[i]!.id) ?? [];
639	    const pdf = atts.find((a) => a.fileType === 'application/pdf');
640	    if (pdf) return pdf;
641	  }
642	  return null;
643	}
644	
645	async function materializeVertexCacheTempFile(buffer: Buffer, fileName: string): Promise<string> {
646	  const safeName = fileName.replace(/[^a-zA-Z0-9._-]/g, '_');
647	  const tempPath = join(tmpdir(), `oracle-chat-vertex-cache-${Date.now()}-${safeName}`);
648	  await writeFile(tempPath, buffer);
649	  return tempPath;
650	}
651	
652	function isVisionCapableRoute(route: OracleModelRoute): boolean {
653	  // Vision detection from the route's flags + a name regex fallback. The
654	  // curated catalog already encodes supportsVision on each route; the
655	  // regex is a defensive belt-and-suspenders in case a catalog entry
656	  // gets misconfigured.
657	  if (route.supportsVision) return true;
658	  return /claude|gpt-4o|gemini|llava|pixtral|qwen.*vl|minicpm/i.test(route.modelId);
659	}
660	
661	function buildContextPackInsert(plan: OraclePromptPlan) {
662	  return {
663	    taskType: plan.taskType,
664	    routeId: plan.routeId,
665	    promptVersion: plan.promptVersion,
666	    schemaVersion: plan.schemaVersion ?? null,
667	    stablePrefixHash: plan.metadata.stablePrefixHash,
668	    semiStableContextHash: plan.metadata.semiStableContextHash ?? null,
669	    retrievedContextHash: plan.metadata.retrievedContextHash ?? null,
670	    dynamicInputHash: plan.metadata.dynamicInputHash,
671	    toolSchemaHash: plan.metadata.toolSchemaHash ?? null,
672	    outputSchemaHash: plan.metadata.outputSchemaHash ?? null,
673	    blocksJson: plan.blocks.map((b) => ({
674	      id: b.id,
675	      label: b.label,
676	      kind: b.kind,
677	      hash: b.hash,
678	      tokenEstimate: b.tokenEstimate ?? null,
679	      cacheEligible: b.cacheEligible,
680	      reasonIncluded: b.reasonIncluded,
681	    })),
682	    retrievalPlanId: plan.metadata.retrievalPlanId ?? null,
683	    selectedDomains: plan.metadata.selectedDomains ?? null,
684	    selectedSourceTypes: plan.metadata.selectedSourceTypes ?? null,
685	    selectedProcessStages: plan.metadata.selectedProcessStages ?? null,
686	    selectedEntityIds: plan.metadata.selectedEntityIds ?? null,
687	    includedMessageIds: plan.metadata.includedMessageIds ?? null,
688	    includedDocumentChunkIds: plan.metadata.includedDocumentChunkIds ?? null,
689	    includedClaimIds: plan.metadata.includedClaimIds ?? null,
690	    includedGapIds: plan.metadata.includedGapIds ?? null,
691	    includedContradictionIds: plan.metadata.includedContradictionIds ?? null,
692	  };
693	}
