// Oracle MCP — knowledge tool registrations.
//
// These tools expose the Oracle's *approved* business knowledge to external AI
// agents (e.g. coding assistants building software for POP Creations / Spruce
// Line) over the Model Context Protocol. They are strictly READ-ONLY and only
// ever surface reviewed content:
//   - search_business_knowledge → approved claims only (searchWithRetrievalPlan
//     filters `c.status = 'approved'` on both the hybrid and fallback paths).
//   - list_brain_sections / get_brain_section → only the current Brain version
//     when its review_status = 'approved'.
//   - list_knowledge_domains → the admin-curated top-domain taxonomy + boundary
//     rules, so an agent can see how the business organizes its knowledge.
//
// Everything routes through the SAME retrieval entry point the employee chat
// uses (`searchWithRetrievalPlan`), so the MCP can never drift from the live
// answer path. Do not add a second retrieval query here — extend the plan.

import { and, asc, eq, inArray } from 'drizzle-orm';
import { z } from 'zod';
import type { McpServer } from '@modelcontextprotocol/sdk/server/mcp.js';
import {
  brainSections,
  brainSectionVersions,
  claimEvidence,
  knowledgeTopDomains,
  sectionClaims,
} from '@oracle/db';
import type { OracleDb } from '@oracle/db/client';
import { buildRetrievalPlanFromQuery, searchWithRetrievalPlan } from '@oracle/ai';

/** Wrap any JSON-serializable payload as an MCP text content result. */
function jsonResult(payload: unknown) {
  return {
    content: [{ type: 'text' as const, text: JSON.stringify(payload, null, 2) }],
  };
}

/** Wrap an error message as an MCP error result (visible to the calling model). */
function errorResult(message: string) {
  return {
    content: [{ type: 'text' as const, text: message }],
    isError: true as const,
  };
}

/**
 * Register all Oracle knowledge tools on the given MCP server. `db` is a
 * read-capable Oracle DB handle (the direct pooler client is fine — every
 * query here is a SELECT).
 */
export function registerOracleKnowledgeTools(server: McpServer, db: OracleDb): void {
  // ── search_business_knowledge ─────────────────────────────────────────
  server.registerTool(
    'search_business_knowledge',
    {
      title: 'Search business knowledge',
      description:
        "Search POP Creations / Spruce Line's approved business knowledge for how the " +
        'company actually operates: processes, systems of record, naming and file rules, ' +
        'approvals, and operational facts. Returns evidence-backed approved claims ranked by ' +
        'semantic relevance. Use this before designing software so the design matches real ' +
        'business process. Optionally scope to specific knowledge domains (see ' +
        'list_knowledge_domains).',
      inputSchema: {
        query: z
          .string()
          .min(2)
          .describe('Natural-language question about a business process, system, or rule.'),
        domains: z
          .array(z.string())
          .optional()
          .describe(
            'Optional knowledge_top_domains IDs to scope the search to (e.g. ' +
              '"operations_systems"). Omit to let the Oracle infer the domains.',
          ),
        limit: z
          .number()
          .int()
          .min(1)
          .max(20)
          .optional()
          .describe('Max claims to return (default 8).'),
        includeEvidence: z
          .boolean()
          .optional()
          .describe('Include verbatim source quotes backing each claim (default false).'),
      },
    },
    async ({ query, domains, limit, includeEvidence }) => {
      const plan = buildRetrievalPlanFromQuery(query, {
        topK: limit ?? 8,
        ...(domains && domains.length > 0 ? { topDomainHints: domains } : {}),
      });
      const claims = await searchWithRetrievalPlan(db, plan);

      let evidenceByClaim = new Map<string, { quote: string; sourceType: string }[]>();
      if (includeEvidence && claims.length > 0) {
        const rows = await db
          .select({
            claimId: claimEvidence.claimId,
            quote: claimEvidence.exactQuote,
            sourceType: claimEvidence.sourceType,
          })
          .from(claimEvidence)
          .where(
            inArray(
              claimEvidence.claimId,
              claims.map((c) => c.id),
            ),
          );
        evidenceByClaim = rows.reduce((acc, r) => {
          const list = acc.get(r.claimId) ?? [];
          // Cap at 3 quotes per claim to keep the payload focused.
          if (list.length < 3) list.push({ quote: r.quote, sourceType: r.sourceType });
          acc.set(r.claimId, list);
          return acc;
        }, new Map<string, { quote: string; sourceType: string }[]>());
      }

      return jsonResult({
        query,
        searchScope: plan.searchScope,
        domainHints: plan.topDomainHints,
        resultCount: claims.length,
        results: claims.map((c) => ({
          id: c.id,
          summary: c.summary,
          claimType: c.claimType,
          impactScore: c.impactScore,
          confidenceScore: c.confidenceScore,
          ...(includeEvidence ? { evidence: evidenceByClaim.get(c.id) ?? [] } : {}),
        })),
        note:
          claims.length === 0
            ? 'No approved claims matched. The knowledge base may not yet cover this topic.'
            : undefined,
      });
    },
  );

  // ── list_knowledge_domains ────────────────────────────────────────────
  server.registerTool(
    'list_knowledge_domains',
    {
      title: 'List knowledge domains',
      description:
        'List the Oracle top-level knowledge domains with their boundary rules ' +
        '(what belongs / does not belong in each). Use this to understand how the ' +
        'business organizes its operational knowledge and to pick `domains` for ' +
        'search_business_knowledge.',
      inputSchema: {
        includeInactive: z
          .boolean()
          .optional()
          .describe('Include domains marked inactive (default false).'),
      },
    },
    async ({ includeInactive }) => {
      const rows = await db
        .select({
          id: knowledgeTopDomains.id,
          name: knowledgeTopDomains.name,
          description: knowledgeTopDomains.description,
          belongsHere: knowledgeTopDomains.belongsHere,
          doesNotBelongHere: knowledgeTopDomains.doesNotBelongHere,
          neighboringDomainIds: knowledgeTopDomains.neighboringDomainIds,
          isActive: knowledgeTopDomains.isActive,
          displayOrder: knowledgeTopDomains.displayOrder,
        })
        .from(knowledgeTopDomains)
        .where(includeInactive ? undefined : eq(knowledgeTopDomains.isActive, true))
        .orderBy(asc(knowledgeTopDomains.displayOrder));

      return jsonResult({ domainCount: rows.length, domains: rows });
    },
  );

  // ── list_brain_sections ───────────────────────────────────────────────
  server.registerTool(
    'list_brain_sections',
    {
      title: 'List Brain sections',
      description:
        'List the Oracle Brain sections — synthesized, human-reviewed narratives of a ' +
        'business process or topic. Only approved sections are returned. Use ' +
        'get_brain_section to read the full markdown of one.',
      inputSchema: {
        domain: z
          .string()
          .optional()
          .describe('Optional knowledge domain to filter sections by.'),
      },
    },
    async ({ domain }) => {
      const conditions = [eq(brainSectionVersions.reviewStatus, 'approved')];
      if (domain) {
        conditions.push(
          eq(brainSections.knowledgeDomain, domain as (typeof brainSections.knowledgeDomain.enumValues)[number]),
        );
      }
      const rows = await db
        .select({
          id: brainSections.id,
          title: brainSections.title,
          category: brainSections.category,
          knowledgeDomain: brainSections.knowledgeDomain,
          relatedDomains: brainSections.relatedDomains,
          versionNumber: brainSectionVersions.versionNumber,
          updatedAt: brainSections.updatedAt,
        })
        .from(brainSections)
        .innerJoin(
          brainSectionVersions,
          eq(brainSectionVersions.id, brainSections.currentVersionId),
        )
        .where(and(...conditions))
        .orderBy(asc(brainSections.knowledgeDomain), asc(brainSections.title));

      return jsonResult({ sectionCount: rows.length, sections: rows });
    },
  );

  // ── get_brain_section ─────────────────────────────────────────────────
  server.registerTool(
    'get_brain_section',
    {
      title: 'Get Brain section',
      description:
        'Read the full markdown of one approved Oracle Brain section by ID, plus the ' +
        'IDs of the approved claims it was synthesized from. Returns an error if the ' +
        'section does not exist or its current version is not approved.',
      inputSchema: {
        id: z.string().describe('The brain_sections.id (e.g. from list_brain_sections).'),
      },
    },
    async ({ id }) => {
      const rows = await db
        .select({
          id: brainSections.id,
          title: brainSections.title,
          category: brainSections.category,
          knowledgeDomain: brainSections.knowledgeDomain,
          relatedDomains: brainSections.relatedDomains,
          markdown: brainSectionVersions.markdown,
          versionNumber: brainSectionVersions.versionNumber,
          changeSummary: brainSectionVersions.changeSummary,
          reviewedAt: brainSectionVersions.reviewedAt,
        })
        .from(brainSections)
        .innerJoin(
          brainSectionVersions,
          eq(brainSectionVersions.id, brainSections.currentVersionId),
        )
        .where(
          and(
            eq(brainSections.id, id),
            eq(brainSectionVersions.reviewStatus, 'approved'),
          ),
        )
        .limit(1);

      const section = rows[0];
      if (!section) {
        return errorResult(
          `No approved Brain section found with id "${id}". Use list_brain_sections to see available sections.`,
        );
      }

      const claimRows = await db
        .select({ claimId: sectionClaims.claimId })
        .from(sectionClaims)
        .where(eq(sectionClaims.sectionId, id));

      return jsonResult({ ...section, sourceClaimIds: claimRows.map((r) => r.claimId) });
    },
  );
}

