  const plan = buildRetrievalPlanFromQuery(query);
  assert.deepEqual(
    plan.topDomainHints,
    expected,
    `Unexpected domain hints for query: ${query}`,
  );
  assert.equal(plan.searchScope, 'domain_filtered', `Expected domain-filtered plan for: ${query}`);
