1	// Oracle MCP — registry access: enablement, search, and contract formatting.
2	//
3	// Enablement (so compiled capabilities can exist without being discoverable):
4	//   - Default: every capability in CAPABILITIES is enabled.
5	//   - ORACLE_MCP_ENABLED_TOOLS (csv) — if set, ONLY these names are enabled.
6	//   - ORACLE_MCP_DISABLED_TOOLS (csv) — these names are always disabled.
7	//   - Disabled overrides enabled (a name in both is disabled).
8	// Disabled capabilities must not appear in tool_search or list_capabilities and
9	// must be rejected by invoke_tool. All three go through getEnabledCapabilities().
10	
11	import { CAPABILITIES, KEYWORD_GROUPS, type Capability } from './capabilities';
12	
13	export const ALWAYS_ON_TOOLS = [
14	  'health',
15	  'list_capabilities',
16	  'tool_search',
17	  'get_capability_details',
18	  'invoke_tool',
19	] as const;
20	
21	const DEFAULT_SEARCH_LIMIT = 8;
22	const MAX_SEARCH_LIMIT = 30;
23	
24	function parseCsvEnv(value: string | undefined): Set<string> {
25	  return new Set(
26	    (value ?? '')
27	      .split(',')
28	      .map((s) => s.trim())
29	      .filter(Boolean),
30	  );
31	}
32	
33	/** Capabilities currently enabled, honoring env overrides (disabled wins). */
34	export function getEnabledCapabilities(env: Record<string, string | undefined> = process.env): Capability[] {
35	  const enabledOverride = parseCsvEnv(env.ORACLE_MCP_ENABLED_TOOLS);
36	  const disabledOverride = parseCsvEnv(env.ORACLE_MCP_DISABLED_TOOLS);
37	  return CAPABILITIES.filter((c) => {
38	    if (disabledOverride.has(c.name)) return false;
39	    if (enabledOverride.size > 0 && !enabledOverride.has(c.name)) return false;
40	    return true;
41	  });
42	}
43	
44	/** Look up an enabled capability by exact name (undefined if missing/disabled). */
45	export function getEnabledCapability(
46	  name: string,
47	  env: Record<string, string | undefined> = process.env,
48	): Capability | undefined {
49	  return getEnabledCapabilities(env).find((c) => c.name === name);
50	}
51	
52	/** Distinct groups among enabled capabilities. */
53	export function getEnabledGroups(env: Record<string, string | undefined> = process.env): string[] {
54	  return [...new Set(getEnabledCapabilities(env).map((c) => c.group))].sort();
55	}
56	
57	export interface SearchHit {
58	  capability: Capability;
59	  score: number;
60	}
61	
62	/**
63	 * Rank enabled capabilities by intent. Scores exact-name, name/title/group/
64	 * description hits, and keyword→group routing. Multi-word queries accumulate
65	 * score on the right capability and drop non-matches (score 0).
66	 */
67	export function searchCapabilities(
68	  query: string,
69	  limit = DEFAULT_SEARCH_LIMIT,
70	  env: Record<string, string | undefined> = process.env,
71	): SearchHit[] {
72	  const caps = getEnabledCapabilities(env);
73	  const cappedLimit = Math.min(Math.max(1, limit), MAX_SEARCH_LIMIT);
74	  const tokens = query.toLowerCase().split(/[^a-z0-9]+/).filter(Boolean);
75	  if (tokens.length === 0) {
76	    return caps.slice(0, cappedLimit).map((capability) => ({ capability, score: 0 }));
77	  }
78	
79	  const hits: SearchHit[] = [];
80	  for (const capability of caps) {
81	    const name = capability.name.toLowerCase();
82	    const title = capability.title.toLowerCase();
83	    const group = capability.group.toLowerCase();
84	    const desc = capability.description.toLowerCase();
85	    let score = 0;
86	    for (const token of tokens) {
87	      if (name === token) score += 10;
88	      else if (name.includes(token)) score += 5;
89	      if (title.includes(token)) score += 4;
90	      if (group === token) score += 4;
91	      const mappedGroups = KEYWORD_GROUPS[token];
92	      if (mappedGroups?.includes(capability.group)) score += 3;
93	      if (desc.includes(token)) score += 2;
94	    }
95	    if (score > 0) hits.push({ capability, score });
96	  }
97	  hits.sort((a, b) => b.score - a.score || a.capability.name.localeCompare(b.capability.name));
98	  return hits.slice(0, cappedLimit);
99	}
100	
101	/** Full structured-text contract for one capability (get_capability_details). */
102	export function formatContract(c: Capability): string {
103	  const invokeExample = JSON.stringify(
104	    { name: c.name, args: c.exampleArgs },
105	    null,
106	    2,
107	  );
108	  return [
109	    `# ${c.name}`,
110	    ``,
111	    `Title: ${c.title}`,
112	    ``,
113	    `Group: ${c.group}`,
114	    ``,
115	    `Safety: tier ${c.safety.tier} ${c.safety.label} — ${c.safety.description}`,
116	    ``,
117	    `Description:`,
118	    c.description,
119	    ``,
120	    `Arguments:`,
121	    c.argsDescription,
122	    ``,
123	    `Example invoke_tool arguments:`,
124	    '```json',
125	    invokeExample,
126	    '```',
127	    ``,
128	    `Common failures:`,
129	    ...c.commonFailures.map((f) => `- ${f}`),
130	    ``,
131	    `Related tools:`,
132	    c.relatedTools.length > 0 ? c.relatedTools.join(', ') : '(none)',
133	  ].join('\n');
134	}
135	
136	/** Compact one-line-ish summary used in tool_search / list_capabilities output. */
137	export function formatSummary(c: Capability): string {
138	  return `${c.name} [${c.group}, tier ${c.safety.tier} ${c.safety.label}] — ${c.description}`;
139	}
140	
141	export { DEFAULT_SEARCH_LIMIT, MAX_SEARCH_LIMIT };

