28	section('always-on tools are exactly the 5 dispatcher tools', () => {
29	  assert.deepEqual(
30	    [...ALWAYS_ON_TOOLS],
31	    ['health', 'list_capabilities', 'tool_search', 'get_capability_details', 'invoke_tool'],
32	  );
33	  const capNames = new Set(CAPABILITIES.map((c) => c.name));
34	  for (const t of ALWAYS_ON_TOOLS) {
35	    assert.ok(!capNames.has(t), `Always-on tool "${t}" must not also be a hidden capability`);
36	  }
37	});
38	
39	// 2. Every capability carries complete, valid metadata + safety tier.
40	section('every capability has complete metadata and a safety tier', () => {
41	  const seen = new Set<string>();
42	  for (const c of CAPABILITIES) {
43	    assert.ok(c.name && !seen.has(c.name), `duplicate/empty capability name: ${c.name}`);
44	    seen.add(c.name);
45	    assert.ok(c.title && c.group && c.description, `${c.name}: missing title/group/description`);
46	    assert.ok(c.argsDescription, `${c.name}: missing argsDescription`);
47	    assert.ok([1, 2, 3].includes(c.safety.tier), `${c.name}: bad safety tier`);
48	    assert.ok(c.safety.label && c.safety.description, `${c.name}: incomplete safety info`);
49	    assert.ok(c.argsSchema instanceof z.ZodType, `${c.name}: argsSchema must be a zod schema`);
50	    assert.ok(Array.isArray(c.commonFailures) && c.commonFailures.length > 0, `${c.name}: needs commonFailures`);
51	    // exampleArgs must satisfy the schema.
52	    const parsed = c.argsSchema.safeParse(c.exampleArgs);
53	    assert.ok(parsed.success, `${c.name}: exampleArgs must validate against argsSchema`);
54	    // relatedTools must reference real capabilities.
55	    for (const rel of c.relatedTools) {
56	      assert.ok(
57	        CAPABILITIES.some((o) => o.name === rel),
58	        `${c.name}: relatedTools references unknown "${rel}"`,
59	      );
60	    }
61	  }
62	});
63	
64	// 3. tool_search finds enabled capabilities by intent (not just exact name).
65	section('tool_search finds capabilities by intent', () => {
66	  const byKeyword = searchCapabilities('naming rules for files');
67	  assert.ok(
68	    byKeyword.some((h) => h.capability.name === 'search_business_knowledge'),
69	    'intent search should surface search_business_knowledge',
70	  );
71	  const byDomain = searchCapabilities('knowledge domains taxonomy');
72	  assert.equal(byDomain[0]?.capability.name, 'list_knowledge_domains', 'taxonomy query should rank domains first');
73	  const byBrain = searchCapabilities('brain section narrative');
74	  assert.ok(byBrain.some((h) => h.capability.group === 'brain'), 'brain query should surface brain group');
75	  // No-match returns empty (not everything).
76	  assert.equal(searchCapabilities('zzzznotarealthing').length, 0);
77	});
78	
79	// 4. Disabled tools disappear from discovery and lookup; disabled overrides enabled.
80	section('enablement overrides hide tools (disabled wins)', () => {
81	  const onlyDomains = getEnabledCapabilities({
82	    ORACLE_MCP_ENABLED_TOOLS: 'list_knowledge_domains',
83	  });
84	  assert.deepEqual(onlyDomains.map((c) => c.name), ['list_knowledge_domains']);
85	
86	  const disabledEnv = { ORACLE_MCP_DISABLED_TOOLS: 'search_business_knowledge' };
87	  assert.ok(
88	    !getEnabledCapabilities(disabledEnv).some((c) => c.name === 'search_business_knowledge'),
89	    'disabled capability must not be enabled',
90	  );
91	  assert.equal(
92	    getEnabledCapability('search_business_knowledge', disabledEnv),
93	    undefined,
94	    'disabled capability must not be found by lookup',
95	  );
96	
97	  // In both lists → disabled wins.
98	  const both = getEnabledCapabilities({
99	    ORACLE_MCP_ENABLED_TOOLS: 'search_business_knowledge',
100	    ORACLE_MCP_DISABLED_TOOLS: 'search_business_knowledge',
101	  });
102	  assert.equal(both.length, 0, 'a name in both enabled and disabled must be disabled');
103	});
104	
105	// 5. get_capability_details output contains the exact invoke_tool shape.
106	section('contract output shows the exact invoke_tool call shape', () => {
107	  const cap = getEnabledCapability('search_business_knowledge');
108	  assert.ok(cap);
109	  const contract = formatContract(cap);
110	  assert.match(contract, /# search_business_knowledge/);
111	  assert.match(contract, /Safety: tier 1 read-only/);
112	  assert.match(contract, /Example invoke_tool arguments:/);
113	  // The embedded JSON must be a real invoke_tool args object: { name, args }.
114	  const json = contract.slice(contract.indexOf('```json') + 7, contract.indexOf('```', contract.indexOf('```json') + 7));
115	  const parsed = JSON.parse(json) as { name: string; args: unknown };
116	  assert.equal(parsed.name, 'search_business_knowledge');
117	  assert.ok(parsed.args && typeof parsed.args === 'object', 'example must carry an args object');
118	  assert.ok(cap.argsSchema.safeParse(parsed.args).success, 'embedded example args must validate');
119	});
120	
121	// 6. Arg validation rejects bad input (the dispatcher relies on this).
122	section('argsSchema rejects invalid input', () => {
123	  const cap = getEnabledCapability('search_business_knowledge')!;
124	  assert.equal(cap.argsSchema.safeParse({}).success, false, 'missing query must fail');
125	  assert.equal(cap.argsSchema.safeParse({ query: 'x', limit: 999 }).success, false, 'limit over max must fail');
126	  assert.equal(cap.argsSchema.safeParse({ query: 'valid question' }).success, true);
127	});
128	
129	// 7. This server is read-only: every capability is tier 1.
130	section('all shipped capabilities are tier-1 read-only', () => {
131	  for (const c of CAPABILITIES) {
132	    assert.equal(c.safety.tier, 1, `${c.name} must be tier 1 in a read-only server`);
133	  }
134	});
135	
136	console.log(`\nAll MCP registry checks passed (${CAPABILITIES.length} capabilities).`);

