$authPath = "C:\Users\ahazan2\AppData\Roaming\xdg.data\com.vercel.cli\auth.json"
$tok = (Get-Content $authPath -Raw | ConvertFrom-Json).token
if (-not $tok) { Write-Output "NO TOKEN"; exit 1 }
$hdr = @{ Authorization = "Bearer $tok" }
$team = Invoke-RestMethod -Uri "https://api.vercel.com/v2/teams?slug=popcre" -Headers $hdr
$teamId = $team.id
Write-Output "teamId resolved: $($teamId.Substring(0,8))…"
$val = ((Select-String -Path "D:\repos\oracle\.env.local" -Pattern '^ORACLE_MCP_TOKEN=(.*)$').Matches[0].Groups[1].Value)
$body = @{ key="ORACLE_MCP_TOKEN"; value=$val; type="encrypted"; target=@("preview") } | ConvertTo-Json
try {
  $resp = Invoke-RestMethod -Method Post -Uri "https://api.vercel.com/v10/projects/prj_rP6Jlima7iK1paffEPhLqxlswGsC/env?teamId=$teamId" -Headers $hdr -ContentType "application/json" -Body $body
  Write-Output "ADDED: key=$($resp.created.key) target=$($resp.created.target -join ',')"
} catch {
  $r = $_.Exception.Response; if ($r) { $sr = New-Object IO.StreamReader($r.GetResponseStream()); Write-Output ("API ERROR: " + $sr.ReadToEnd()) } else { Write-Output ("ERROR: " + $_.Exception.Message) }
}
